const results = $.steps.searchWeb.response.results || [];
const depth = parseInt($.input.depth || '3', 10);
const topUrls = results.slice(0, depth).map(r => r.url).filter(Boolean);
const summaries = results.map((r, i) => ({ index: i + 1, title: r.title || '', url: r.url, snippet: (r.text || '').slice(0, 300), publishedDate: r.publishedDate || '' }));
return { topUrls, summaries, totalResults: results.length };

const summaries = $.steps.selectTopPages.output.summaries;
const iterations = $.steps.scrapePages.response.iterations || [];
const topUrls = $.steps.selectTopPages.output.topUrls;

let researchData = 'SEARCH RESULTS OVERVIEW (' + summaries.length + ' sources found):\n\n';
summaries.forEach(s => {
  researchData += '[' + s.index + '] ' + s.title + '\n';
  researchData += '    URL: ' + s.url + '\n';
  if (s.publishedDate) researchData += '    Published: ' + s.publishedDate + '\n';
  researchData += '    Preview: ' + s.snippet + '\n\n';
});

researchData += '\nDEEP-SCRAPED PAGE CONTENTS:\n\n';
iterations.forEach((iter, i) => {
  const url = topUrls[i] || 'Unknown';
  const resp = (iter.scrapePage && iter.scrapePage.response && iter.scrapePage.response.data) ? iter.scrapePage.response.data : {};
  const md = resp.markdown || '';
  researchData += '=== SOURCE [' + (i + 1) + ']: ' + url + ' ===\n';
  researchData += md.slice(0, 3000) + '\n\n';
});

return { researchData, sourceCount: summaries.length, scrapedCount: iterations.length };

const question = $.input.question;
const data = $.steps.compileResearch.output;

let prompt = 'You are a senior research analyst. Answer the following research question by synthesizing the web sources provided below. Include proper citations using [Source N] notation.\n\n';
prompt += 'RESEARCH QUESTION: ' + question + '\n\n';
prompt += data.researchData + '\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Synthesize findings across all sources, do not just summarize each source individually\n';
prompt += '- Use [Source N] citations throughout to attribute claims\n';
prompt += '- Identify areas of consensus and disagreement between sources\n';
prompt += '- Note any gaps in the available information\n';
prompt += '- Use Slack mrkdwn format: *bold* (NOT **bold**), _italic_, numbered lists, > for quotes\n\n';
prompt += 'Return ONLY valid JSON with this structure:\n';
prompt += '{\n';
prompt += '  "answer": "comprehensive 2-4 paragraph answer to the research question with [Source N] citations",\n';
prompt += '  "keyFindings": ["finding 1 with citation", "finding 2 with citation"],\n';
prompt += '  "consensus": "what sources agree on",\n';
prompt += '  "disagreements": "where sources conflict or differ",\n';
prompt += '  "gaps": "what information is missing or needs further research",\n';
prompt += '  "confidence": "high/medium/low — overall confidence in the answer",\n';
prompt += '  "sources": [{ "number": 1, "title": "source title", "url": "url", "relevance": "why this source matters" }]\n';
prompt += '}\n';

return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { answer: raw.slice(0, 3000), keyFindings: [], sources: [], confidence: 'unknown', text: raw }; }

const ai = $.steps.parseAI.output;
const question = $.input.question;
const sourceCount = $.steps.compileResearch.output.sourceCount;
const scrapedCount = $.steps.compileResearch.output.scrapedCount;

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Research Report', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Question:* ' + question } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Confidence:* ' + (ai.confidence || 'N/A') + ' | *Sources:* ' + sourceCount + ' found, ' + scrapedCount + ' deep-scraped' } });
blocks.push({ type: 'divider' });

// Main answer — split if long
const answer = ai.answer || ai.text || 'No answer generated.';
const answerChunks = [];
for (let i = 0; i < answer.length; i += 2900) { answerChunks.push(answer.slice(i, i + 2900)); }
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Answer*' } });
answerChunks.forEach(chunk => {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: chunk } });
});
blocks.push({ type: 'divider' });

// Key findings
if (ai.keyFindings && ai.keyFindings.length) {
  let findingsText = '*Key Findings*\n';
  ai.keyFindings.forEach((f, i) => { findingsText += (i + 1) + '. ' + f + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: findingsText.slice(0, 3000) } });
  blocks.push({ type: 'divider' });
}

// Consensus & disagreements
if (ai.consensus) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Areas of Consensus*\n' + ai.consensus } });
}
if (ai.disagreements) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Disagreements*\n' + ai.disagreements } });
}
if (ai.gaps) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Information Gaps*\n' + ai.gaps } });
}
blocks.push({ type: 'divider' });

// Sources
if (ai.sources && ai.sources.length) {
  let srcText = '*Sources*\n';
  ai.sources.forEach(s => {
    srcText += '[' + s.number + '] <' + s.url + '|' + (s.title || s.url) + '>\n';
  });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: srcText.slice(0, 3000) } });
}

blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Researched via Exa + Firecrawl + Claude AI' }] });

const fallback = 'Research Report: ' + question.slice(0, 100) + ' (' + sourceCount + ' sources analyzed)';

return { blocks, fallback };
